/* ============================================================================
 * translations.js — EN / 中文 text dictionary + runtime for the factory portal.
 *
 * Text swap only. Supabase data (factory names, brand names, SKU numbers,
 * product names, file names, dates) is never translated — those reach the UI as
 * interpolated {values}, not keys.
 *
 * Usage:
 *   - Static HTML:  data-i18n="key" (innerHTML), data-i18n-ph="key" (placeholder),
 *                   data-i18n-aria="key" (aria-label), data-i18n-label="key" (label attr).
 *   - JS strings:   t('key')  or  t('key', { n: 5, name: 'Acme' })
 *   - Toggle:       Lang.set('en' | 'zh')   (persisted in localStorage 'portal_lang')
 *   - Pages may define window.onLangChange(lang) to re-render dynamic panes.
 *
 * Intentionally kept in English (per spec): international standard / certification
 * / audit proper names (ISO 9001, OEKO-TEX, BSCI, FDA, GMP, …), courier & retailer
 * brand names (SF Express, UPS, FedEx, DHL, Walmart, P&G, …), and the literal
 * CA Prop 65 legal warning sentence. Their surrounding labels ARE translated.
 * ========================================================================== */
